import{_ as t,o as r,c as i,a2 as s}from"./chunks/framework.Cuq8tsM6.js";const p=JSON.parse('{"title":"Paiement des Revenus","description":"","frontmatter":{"title":"Paiement des Revenus"},"headers":[],"relativePath":"docs/fr/publishers/payouts.md","filePath":"docs/fr/publishers/payouts.md"}'),a={name:"docs/fr/publishers/payouts.md"};function n(o,e,l,d,u,m){return r(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="gestion-des-revenus-et-paiements" tabindex="-1">Gestion des Revenus et Paiements <a class="header-anchor" href="#gestion-des-revenus-et-paiements" aria-label="Permalink to &quot;Gestion des Revenus et Paiements&quot;">​</a></h1><p>Suivez vos gains en temps réel et optimisez votre trésorerie pour éviter les frais.</p><h2 id="suivi-du-p-l-wallet" tabindex="-1">Suivi du P&amp;L (Wallet) <a class="header-anchor" href="#suivi-du-p-l-wallet" aria-label="Permalink to &quot;Suivi du P&amp;L (Wallet)&quot;">​</a></h2><div class="gi-accent-box"><p style="margin:0 0 0.5rem;">Vos revenus sont visibles en temps réel sur la plateforme.</p><p style="margin:0;">Consultez à tout moment votre <strong>Solde Disponible</strong> = <em>(Revenus validés) - (Retraits effectués)</em>.</p></div><h2 id="politique-de-retrait-et-frais" tabindex="-1">Politique de Retrait et Frais <a class="header-anchor" href="#politique-de-retrait-et-frais" aria-label="Permalink to &quot;Politique de Retrait et Frais&quot;">​</a></h2><p>Nous encourageons le regroupement des paiements pour limiter les frictions administratives.</p><div class="gi-value-grid"><div class="gi-value-card" style="border-color:var(--gi-tint-green-text);background:var(--gi-tint-green-bg);"><strong style="color:var(--gi-tint-green-text);">1️⃣ Le Premier Retrait</strong><div style="font-size:1.75rem;font-weight:800;color:var(--gi-tint-green-text);line-height:1.2;margin:0.5rem 0;">GRATUIT</div><p style="margin:0;">Votre tout premier virement est <strong>100% gratuit</strong>, quel que soit le montant. Aucun frais de gestion.</p></div><div class="gi-value-card"><strong>🔄 Les Retraits Suivants</strong><div style="font-size:1.75rem;font-weight:800;line-height:1.2;margin:0.5rem 0;">5% <span style="font-size:1rem;font-weight:400;color:var(--vp-c-text-2);">de frais</span></div><p style="margin:0 0 0.5rem;">Des frais de gestion s&#39;appliquent sur le montant demandé.</p><p style="margin:0;font-size:0.8125rem;color:var(--vp-c-text-2);"><em>Ex: Pour 1 000€ retirés, vous recevez 950€.</em></p></div></div><h2 id="comment-eviter-les-frais-de-5" tabindex="-1">Comment éviter les frais de 5% ? <a class="header-anchor" href="#comment-eviter-les-frais-de-5" aria-label="Permalink to &quot;Comment éviter les frais de 5% ?&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card" style="border-color:var(--vp-c-brand-1);"><strong>Option A : Le &quot;Cumul&quot;</strong><p>Laissez vos revenus s&#39;accumuler sur votre cagnotte.</p><ul style="margin:0;padding-left:1.25rem;font-size:0.875rem;color:var(--vp-c-text-2);"><li><strong>Avantage :</strong> En espaçant vos retraits, retirez vos revenus une fois par an, en un retrait groupé <strong>sans frais</strong>.</li></ul></div><div class="gi-value-card" style="border-color:var(--vp-c-brand-1);"><strong>Option B : Le Réinvestissement</strong><p>Utilisez votre solde pour financer vos propres campagnes d&#39;acquisition (Asile Colis ou Emailing).</p><ul style="margin:0;padding-left:1.25rem;font-size:0.875rem;color:var(--vp-c-text-2);"><li><strong>Avantage :</strong> 1€ gagné = 1€ réinvesti en trafic. Aucune friction bancaire, transfert immédiat.</li></ul></div></div><div class="gi-info-box"><h4>💡 Pourquoi cette politique ?</h4><ol style="margin:0;padding-left:1.25rem;"><li style="margin-bottom:0.5rem;"><strong>Réduction de l&#39;Admin :</strong> Limiter le volume de petits virements nous permet de maintenir des coûts de plateforme bas.</li><li><strong>Sécurité (Buffer) :</strong> Ce délai de trésorerie sécurise les fonds en cas d&#39;impayés annonceurs, vous garantissant d&#39;être payé même si l&#39;annonceur a du retard.</li></ol></div>',10)])])}const c=t(a,[["render",n]]);export{p as __pageData,c as default};
